   321→  @Override
   322→  public void visit(OWLDataMinCardinality ce) {
   323→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   324→    setDataPropertiesWithCardinality(ce);
   325→  }
   326→
   327→  @Override
   328→  public void visit(OWLDataMaxCardinality ce) {
   329→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   330→    setDataPropertiesWithCardinality(ce);
   331→  }
   332→
   333→  @Override
   334→  public void visit(OWLDataExactCardinality ce) {
   335→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   336→    setDataPropertiesWithCardinality(ce);
   337→  }
   338→
   339→  @Override
   340→  public void visit(OWLDataOneOf ce) {
   341→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   342→    for (OWLLiteral value : ce.getValues()) {
   343→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   344→    }
   345→    propertyName = "";
   346→  }
   347→
   348→  @Override
   349→  public void visit(OWLDataComplementOf ce) {
   350→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   351→    propertyName = "";
   352→  }
   353→
   354→  @Override
   355→  public void visit(OWLDataHasValue ce) {
   356→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   357→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   358→      propertyName = cleanName(nameResolver.resolve(property));
   359→      dataPropertyNames.add(propertyName);
   360→    }
   361→    propertyName = "";
   362→  }
   363→
   364→  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
   365→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   366→      propertyName = cleanName(nameResolver.resolve(property));
   367→      objectPropertyNames.add(propertyName);
   368→
   369→      final String propName = propertyName;
   370→      RestrictionInfo.from(ce).ifPresent(info ->
   371→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   372→
   373→      // Detect taxonomy patterns
   374→      taxonomyDetector.detect(propertyName, ce.getFiller())
   375→          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));
   376→
   377→      if (ce.getFiller().isOWLClass()) {
   378→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   379→      }
   380→    }
   381→    propertyName = "";
   382→  }
   383→
   384→  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
   385→      Set<OWLClassExpression> ranges,
   386→      Set<OWLObjectProperty> properties) {
   387→    if (propertyName.isEmpty()) {
   388→      for (OWLObjectProperty property : properties) {
   389→        propertyName = cleanName(nameResolver.resolve(property));
   390→        objectPropertyNames.add(propertyName);
   391→        for (OWLClassExpression range : ranges) {
   392→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   393→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   394→              range.accept(this);
   395→            }
   396→          }
   397→        }
   398→      }
   399→
   400→      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
   401→        propertyName = cleanName(nameResolver.resolve(property));
   402→        dataPropertyNames.add(propertyName);
   403→        for (OWLClassExpression range : ranges) {
   404→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   405→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   406→              range.accept(this);
   407→            }
   408→          }
   409→        }
   410→      }
   411→    } else {
   412→      for (OWLClassExpression range : ranges) {
   413→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   414→        if (rangeClasses.size() != 1) {
   415→          range.accept(this);
   416→        } else if (!range.asOWLClass().equals(owlThing)) {
   417→          // Range is tracked in objectPropertyRanges via visitor methods
   418→        } else {
   419→          logger.fine("Ignoring owl:Thing range " + propertyName);
   420→        }
   421→      }
   422→    }
   423→    propertyName = "";
   424→  }
   425→
   426→  private void setBooleanCombinationDataProperties(OWLDataRange expression,
   427→      Set<OWLDataRange> ranges,
   428→      Set<OWLDataProperty> properties) {
   429→    if (propertyName.isEmpty()) {
   430→      for (OWLDataProperty property : properties) {
   431→        propertyName = cleanName(nameResolver.resolve(property));
   432→        dataPropertyNames.add(propertyName);
   433→        for (OWLDataRange range : ranges) {
   434→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   435→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   436→              range.accept(this);
   437→            }
   438→          }
   439→        }
   440→      }
   441→
   442→      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
   443→        propertyName = cleanName(nameResolver.resolve(property));
   444→        objectPropertyNames.add(propertyName);
   445→        for (OWLDataRange range : ranges) {
   446→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   447→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   448→              range.accept(this);
   449→            }
   450→          }
   451→        }
   452→      }
   453→    } else {
   454→      for (OWLDataRange range : ranges) {
   455→        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
   456→        if (rangeDatatypes.size() != 1) {
   457→          range.accept(this);
   458→        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
   459→          // Range is tracked in dataPropertyRanges via visitor methods
   460→        } else {
   461→          logger.fine("Ignoring owl:Thing range " + propertyName);
   462→        }
   463→      }
   464→    }
   465→    propertyName = "";
   466→  }
   467→
   468→  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
   469→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   470→      propertyName = cleanName(nameResolver.resolve(property));
   471→      dataPropertyNames.add(propertyName);
   472→
   473→      final String propName = propertyName;
   474→      RestrictionInfo.from(ce).ifPresent(info ->
   475→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   476→
   477→      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
   478→        dataPropertyRanges.put(propertyName, datatype);
   479→      }
   480→    }
   481→    propertyName = "";
   482→  }
   483→
   484→  // Getters for type-safe storage (unmodifiable views)
   485→  public Map<String, Set<RestrictionInfo>> getRestrictions() {
   486→    return Collections.unmodifiableMap(restrictions);
   487→  }
   488→
   489→  public Multimap<String, OWLClass> getObjectPropertyRanges() {
   490→    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
   491→  }
   492→
   493→  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
   494→    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
   495→  }
   496→
   497→  public Set<String> getObjectPropertyNames() {
   498→    return Collections.unmodifiableSet(objectPropertyNames);
   499→  }
   500→
   501→  public Set<String> getDataPropertyNames() {
   502→    return Collections.unmodifiableSet(dataPropertyNames);
   503→  }
   504→
   505→  public Map<String, TaxonomyInfo> getTaxonomyPatterns() {
   506→    return Collections.unmodifiableMap(taxonomyPatterns);
   507→  }
   508→
   509→  public OWLOntology getOntology() {
   510→    return onto;
   511→  }
   512→
   513→  private static String cleanName(String propertyName) {
   514→    return Objects.requireNonNull(propertyName);
   515→  }
   516→}

