   621→  /**
   622→   * Adds a taxonomy property to the schema.
   623→   *
   624→   * @param schema the schema to add the property to
   625→   * @param name the property name
   626→   * @param description the property description
   627→   * @param label the property label
   628→   * @param enumValues the list of allowed enum values
   629→   * @param restrictions the restrictions for this property
   630→   */
   631→  private void addTaxonomyPropertyToSchema(
   632→      Schema<?> schema,
   633→      String name,
   634→      String description,
   635→      String label,
   636→      List<String> enumValues,
   637→      Set<RestrictionInfo> restrictions) {
   638→    TaxonomyPropertyMapper mapper = new TaxonomyPropertyMapper(
   639→        context, name, description, label, enumValues, restrictions);
   640→    schema.addProperty(mapper.getName(), mapper.getTaxonomySchemaObject());
   641→    if (mapper.isRequired()) {
   642→      schema.addRequiredItem(mapper.getName());
   643→    }
   644→  }
   645→
   646→  /**
   647→   * Logs a warning when no properties were found for a class.
   648→   *
   649→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   650→   * on the property restrictions, or that the schema label doesn't match.
   651→   *
   652→   * @param analyzedClass the class that had no mappable properties
   653→   * @param axioms all collected axioms (for diagnostic output)
   654→   */
   655→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   656→    logger.warning("No properties with " + OntologyConstants.apiLabel
   657→        + " annotation found for: " + analyzedClass);
   658→
   659→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   660→        .flatMap(Collection::stream)
   661→        .toList();
   662→
   663→    if (!allAxioms.isEmpty()) {
   664→      allAxioms.stream()
   665→          .map(axiom -> axiom.getSuperClass().toString())
   666→          .forEach(s -> logger.warning("\tPossible property: " + s));
   667→    }
   668→  }
   669→
   670→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   671→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   672→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   673→
   674→    return subAx.stream().filter(ax -> ax.annotations()
   675→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   676→      OWLClassExpression superCls = ax.getSuperClass();
   677→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   678→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   679→              .isEmpty()) || superCls.classesInSignature()
   680→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   681→    }).collect(Collectors.toList());
   682→  }
   683→
   684→  public String getSchemaName() {
   685→    return nameResolver.resolve(cls);
   686→  }
   687→
   688→  private String getSchemaAnnotation(String schema) {
   689→    return '"' + schema + '"' + "^^xsd:string";
   690→  }
   691→
   692→  private String taxonomyName(String taxonomy_name) {
   693→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   694→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   695→    }
   696→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   697→  }
   698→
   699→  private String getLabel(final OWLEntity entity) {
   700→    return OntologyUtil.getTitle(entity, context.getOntology());
   701→  }
   702→
   703→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   704→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   705→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   706→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   707→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   708→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   709→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   710→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   711→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   712→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   713→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   714→          if (superClass.isOWLClass()) {
   715→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   716→          }
   717→          if (owlSubClassOfAxiom.annotations()
   718→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   719→            superClassAxioms.add(owlSubClassOfAxiom);
   720→          }
   721→          return superClassAxioms.stream();
   722→        });
   723→  }
   724→
   725→}
