  @Test
  void testMultipleRestrictionsSameProperty() {
    // TestClass subClassOf (hasProperty min 1 TargetClass) and (hasProperty max 5 TargetClass)
    var minRestriction = factory.getOWLObjectMinCardinality(1, hasProperty, targetClass);
    var maxRestriction = factory.getOWLObjectMaxCardinality(5, hasProperty, targetClass);

    manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, minRestriction));
    manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, maxRestriction));

    SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
    testClass.accept(visitor);

    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();
    Set<RestrictionInfo> infos = restrictions.get("hasProperty");
    assertEquals(2, infos.size(), "Should have two restrictions on same property");

    boolean hasMin = infos.stream().anyMatch(r -> r instanceof RestrictionInfo.MinCardinality);
    boolean hasMax = infos.stream().anyMatch(r -> r instanceof RestrictionInfo.MaxCardinality);
    assertTrue(hasMin && hasMax, "Should have both min and max cardinality restrictions");
  }

  @Test
  void testCollectionsAreEncapsulated() {
    // Add a restriction so the collections are not empty
    var restriction = factory.getOWLObjectMinCardinality(1, hasProperty, targetClass);
    var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
    manager.addAxiom(ontology, axiom);

    SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
    testClass.accept(visitor);

    // Verify collections are returned (encapsulation check)
    assertNotNull(visitor.getRestrictions(), "Should return restrictions map");
    assertNotNull(visitor.getObjectPropertyNames(), "Should return object property names");
    assertNotNull(visitor.getDataPropertyNames(), "Should return data property names");

    // Verify the collections have content
    assertFalse(visitor.getRestrictions().isEmpty(), "Should have restrictions");
    assertFalse(visitor.getObjectPropertyNames().isEmpty(), "Should have object properties");
  }

  @Test
  void testObjectUnionOf() {
    // TestClass subClassOf (hasProperty some (TargetClass or OWLThing))
    OWLClass anotherClass = factory.getOWLClass(IRI.create(BASE_IRI + "AnotherClass"));
    var union = factory.getOWLObjectUnionOf(targetClass, anotherClass);
    var restriction = factory.getOWLObjectSomeValuesFrom(hasProperty, union);
    var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
    manager.addAxiom(ontology, axiom);

    SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
    testClass.accept(visitor);

    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();
    assertTrue(restrictions.containsKey("hasProperty"), "Should handle union in restriction");
  }

  @Test
  void testProcessedClassesCycleDetection() {
    // Create a cycle: TestClass subClassOf TargetClass, TargetClass subClassOf TestClass
    var axiom1 = factory.getOWLSubClassOfAxiom(testClass, targetClass);
    var axiom2 = factory.getOWLSubClassOfAxiom(targetClass, testClass);
    manager.addAxiom(ontology, axiom1);
    manager.addAxiom(ontology, axiom2);

    // Should not throw StackOverflowError due to processedClasses tracking
    assertDoesNotThrow(() -> {
      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);
    }, "Should handle circular class hierarchies");
  }

