  @Nested
  class HierarchyTraversal {

    @Test
    void testSuperClassRestrictionsAreCollected() {
      OWLClass parentClass = factory.getOWLClass(IRI.create(BASE_IRI + "ParentClass"));
      OWLDataProperty parentProp = factory.getOWLDataProperty(IRI.create(BASE_IRI + "parentProp"));

      // Parent has a restriction
      OWLDatatype stringType = factory.getStringOWLDatatype();
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(parentClass,
          factory.getOWLDataSomeValuesFrom(parentProp, stringType)));
      // Test class is subclass of parent
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, parentClass));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      // Should collect parent's restriction
      assertTrue(visitor.getDataPropertyNames().contains("parentProp"));
    }

    @Test
    void testMultipleSuperClassRestrictionsAreCollected() {
      OWLClass parent1 = factory.getOWLClass(IRI.create(BASE_IRI + "Parent1"));
      OWLClass parent2 = factory.getOWLClass(IRI.create(BASE_IRI + "Parent2"));
      OWLDataProperty prop1 = factory.getOWLDataProperty(IRI.create(BASE_IRI + "prop1"));
      OWLDataProperty prop2 = factory.getOWLDataProperty(IRI.create(BASE_IRI + "prop2"));

      OWLDatatype stringType = factory.getStringOWLDatatype();
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(parent1,
          factory.getOWLDataSomeValuesFrom(prop1, stringType)));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(parent2,
          factory.getOWLDataSomeValuesFrom(prop2, stringType)));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, parent1));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, parent2));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getDataPropertyNames().contains("prop1"));
      assertTrue(visitor.getDataPropertyNames().contains("prop2"));
    }
  }

