      var ranges = visitor.getObjectPropertyRanges();
      OWLClass newClass = factory.getOWLClass(IRI.create(BASE_IRI + "NewClass"));
      org.junit.jupiter.api.Assertions.assertThrows(UnsupportedOperationException.class, () ->
