  @Nested
  class EdgeCases {

    @Test
    void testEmptyClassHasNoRestrictions() {
      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getRestrictions().isEmpty());
      assertTrue(visitor.getObjectPropertyNames().isEmpty());
      assertTrue(visitor.getDataPropertyNames().isEmpty());
