    @Test
    void testObjectHasValueCollectsPropertyName() {
      var individual = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "individual1"));
      var restriction = factory.getOWLObjectHasValue(hasProperty, individual);
      var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
      manager.addAxiom(ontology, axiom);

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getObjectPropertyNames().contains("hasProperty"));
