    @Test
    void testDataHasValueCollectsPropertyName() {
      var literal = factory.getOWLLiteral("defaultValue");
      var restriction = factory.getOWLDataHasValue(hasDataProperty, literal);
      var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
      manager.addAxiom(ontology, axiom);

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getDataPropertyNames().contains("hasDataProperty"));
    }

    @Test
    void testMixedDataAndObjectPropertiesCollectedSeparately() {
      var objRestriction = factory.getOWLObjectSomeValuesFrom(hasProperty, targetClass);
      OWLDatatype stringType = factory.getStringOWLDatatype();
      var dataRestriction = factory.getOWLDataSomeValuesFrom(hasDataProperty, stringType);

      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, objRestriction));
      manager.addAxiom(ontology, factory.getOWLSubClassOfAxiom(testClass, dataRestriction));

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getObjectPropertyNames().contains("hasProperty"));
      assertTrue(visitor.getDataPropertyNames().contains("hasDataProperty"));
      // Verify they're not mixed up
      assertFalse(visitor.getObjectPropertyNames().contains("hasDataProperty"));
      assertFalse(visitor.getDataPropertyNames().contains("hasProperty"));
    }

    @Test
    void testObjectIntersectionOf() {
      OWLClass anotherClass = factory.getOWLClass(IRI.create(BASE_IRI + "AnotherClass"));
      var intersection = factory.getOWLObjectIntersectionOf(targetClass, anotherClass);
      var restriction = factory.getOWLObjectSomeValuesFrom(hasProperty, intersection);
      var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
      manager.addAxiom(ontology, axiom);

      SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
      testClass.accept(visitor);

      assertTrue(visitor.getRestrictions().containsKey("hasProperty"));
    }
  }
}

