   114→### Phase 1: Create Type-Safe Restriction Data Structure ✅
   115→
   116→**Created:** `src/main/java/com/grl/component/asg/RestrictionInfo.java`
   117→
   118→Sealed interface with 17 record subtypes representing each OWL restriction type:
   119→
   120→```java
   121→public sealed interface RestrictionInfo {
   122→
   123→  Object expression();
   124→
   125→  default OptionalInt cardinality() {
   126→    return OptionalInt.empty();
   127→  }
   128→
   129→  default Optional<? extends OWLPropertyRange> filler() {
   130→    return Optional.empty();
   131→  }
   132→
   133→  // Cardinality restrictions
   134→  record MinCardinality(OWLObjectMinCardinality expression) implements RestrictionInfo {...
   135→  }
   136→
   137→  record MaxCardinality(OWLObjectMaxCardinality expression) implements RestrictionInfo {...
   138→  }
   139→
   140→  record ExactCardinality(OWLObjectExactCardinality expression) implements RestrictionInfo {...
   141→  }
   142→
   143→  // Data cardinality restrictions
   144→  record DataMinCardinality(OWLDataMinCardinality expression) implements RestrictionInfo {...
   145→  }
   146→
   147→  record DataMaxCardinality(OWLDataMaxCardinality expression) implements RestrictionInfo {...
   148→  }
   149→
   150→  record DataExactCardinality(OWLDataExactCardinality expression) implements RestrictionInfo {...
   151→  }
   152→
   153→  // Value restrictions
   154→  record SomeValuesFrom(OWLObjectSomeValuesFrom expression) implements RestrictionInfo {...
   155→  }
   156→
   157→  record AllValuesFrom(OWLObjectAllValuesFrom expression) implements RestrictionInfo {...
   158→  }
   159→
   160→  record DataSomeValuesFrom(OWLDataSomeValuesFrom expression) implements RestrictionInfo {...
   161→  }
   162→
   163→  record DataAllValuesFrom(OWLDataAllValuesFrom expression) implements RestrictionInfo {...
   164→  }
   165→
   166→  // Other restrictions
   167→  record HasValue(OWLObjectHasValue expression) implements RestrictionInfo {
   168→
   169→  }
   170→
   171→  record DataHasValue(OWLDataHasValue expression) implements RestrictionInfo {
   172→
   173→  }
   174→
   175→  record OneOf(OWLObjectOneOf expression) implements RestrictionInfo {
   176→
   177→  }
   178→
   179→  record DataOneOf(OWLDataOneOf expression) implements RestrictionInfo {
   180→
   181→  }
   182→
   183→  record UnionOf(OWLObjectUnionOf expression) implements RestrictionInfo {
   184→
   185→  }
   186→
   187→  record IntersectionOf(OWLObjectIntersectionOf expression) implements RestrictionInfo {
   188→
   189→  }
   190→
   191→  record ComplementOf(OWLObjectComplementOf expression) implements RestrictionInfo {
   192→
   193→  }
   194→
   195→  // Factory method with pattern matching
   196→  static Optional<RestrictionInfo> from(OWLClassExpression expr) {
   197→    return Optional.ofNullable(switch (expr) {
   198→      case OWLObjectMinCardinality c -> new MinCardinality(c);
   199→      case OWLObjectMaxCardinality c -> new MaxCardinality(c);
   200→      case OWLObjectExactCardinality c -> new ExactCardinality(c);
   201→      case OWLObjectSomeValuesFrom c -> new SomeValuesFrom(c);
   202→      case OWLObjectAllValuesFrom c -> new AllValuesFrom(c);
   203→      case OWLObjectHasValue c -> new HasValue(c);
   204→      case OWLObjectOneOf c -> new OneOf(c);
   205→      case OWLObjectUnionOf c -> new UnionOf(c);
   206→      case OWLObjectIntersectionOf c -> new IntersectionOf(c);
   207→      case OWLObjectComplementOf c -> new ComplementOf(c);
   208→      case OWLDataMinCardinality c -> new DataMinCardinality(c);
   209→      case OWLDataMaxCardinality c -> new DataMaxCardinality(c);
   210→      case OWLDataExactCardinality c -> new DataExactCardinality(c);
   211→      case OWLDataSomeValuesFrom c -> new DataSomeValuesFrom(c);
   212→      case OWLDataAllValuesFrom c -> new DataAllValuesFrom(c);
   213→      case OWLDataHasValue c -> new DataHasValue(c);
   214→      case OWLDataOneOf c -> new DataOneOf(c);
   215→      default -> null;
   216→    });
   217→  }
   218→
   219→  // Apply restriction to OpenAPI ArraySchema with correct OWL semantics
   220→  default void applyToArraySchema(io.swagger.v3.oas.models.media.ArraySchema schema) {
   221→    switch (this) {
   222→      case MinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   223→      case MaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   224→      case ExactCardinality r -> {
   225→        schema.setMinItems(r.expression().getCardinality());
   226→        schema.setMaxItems(r.expression().getCardinality());
   227→      }
   228→      case DataMinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   229→      case DataMaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   230→      case DataExactCardinality r -> {
   231→        schema.setMinItems(r.expression().getCardinality());
   232→        schema.setMaxItems(r.expression().getCardinality());
   233→      }
   234→      case SomeValuesFrom r -> schema.setMinItems(1); // "at least one from this set"
   235→      case AllValuesFrom r -> {
   236→      } // type constraint only, NO cardinality
   237→      case DataSomeValuesFrom r -> schema.setMinItems(1);
   238→      case DataAllValuesFrom r -> {
   239→      } // type constraint only
   240→      default -> {
   241→      }
   242→    }
   243→  }
   244→
   245→  // Check if restriction implies property is required (minCardinality >= 1)
   246→  default boolean impliesRequired() {
   247→    return switch (this) {
   248→      case MinCardinality r -> r.expression().getCardinality() >= 1;
   249→      case ExactCardinality r -> r.expression().getCardinality() >= 1;
   250→      case DataMinCardinality r -> r.expression().getCardinality() >= 1;
   251→      case DataExactCardinality r -> r.expression().getCardinality() >= 1;
   252→      case SomeValuesFrom r -> true;
   253→      case DataSomeValuesFrom r -> true;
   254→      default -> false;
   255→    };
   256→  }
   257→
   258→  // Check if restriction implies array (cardinality > 1 or someValuesFrom)
   259→  default boolean impliesArray() {
   260→    return switch (this) {
   261→      case MinCardinality r -> r.expression().getCardinality() > 1;
   262→      case MaxCardinality r -> r.expression().getCardinality() > 1;
   263→      case ExactCardinality r -> r.expression().getCardinality() > 1;
   264→      case DataMinCardinality r -> r.expression().getCardinality() > 1;
   265→      case DataMaxCardinality r -> r.expression().getCardinality() > 1;
   266→      case DataExactCardinality r -> r.expression().getCardinality() > 1;
   267→      case SomeValuesFrom r -> true;
   268→      case DataSomeValuesFrom r -> true;
   269→      default -> false;
   270→    };
   271→  }
   272→}
   273→```
   274→
   275→**Key Design Decisions:**
   276→
   277→- Sealed interface ensures exhaustive pattern matching
   278→- Record types for immutability and conciseness
   279→- Factory method `from()` uses pattern matching for type discrimination
   280→- Helper methods `applyToArraySchema()`, `impliesRequired()`, `impliesArray()` centralize OWL
   281→  semantics
   282→- Direct access to OWL expression via `expression()` method
