   511→class DataPropertyMapper {
   512→
   513→  private final Set<RestrictionInfo> restrictions;
   514→
   515→  public DataPropertyMapper(String name, String label, String description,
   516→      @Nullable Object exampleValue,
   517→      Boolean isFunctional, List<RestrictionInfo> restrictions,
   518→      List<String> valuesFromDataRestrictions_ranges, List<String> type,
   519→      Boolean array, Boolean isRequired) {
   520→    // ... field assignments
   521→    this.restrictions = Set.copyOf(restrictions);
   522→  }
   523→
   524→  private ArraySchema composedSchema() {
   525→    ArraySchema array = new ArraySchema();
   526→    ComposedSchema composedSchema = new ComposedSchema();
   527→
   528→    // NEW: Pattern matching for boolean combinations
   529→    for (RestrictionInfo restriction : this.restrictions) {
   530→      for (String item : this.type) {
   531→        Schema<?> schema = createSchemaForType(item);
   532→        isRequired |= restriction.impliesRequired();
   533→        switch (restriction) {
   534→          case UnionOf _union -> composedSchema.addAnyOfItem(withExample(schema));
   535→          case IntersectionOf _intersection -> composedSchema.addAllOfItem(withExample(schema));
   536→          default -> throw new IllegalStateException("Unexpected value: " + restriction);
   537→        }
   538→      }
   539→    }
   540→    array.setItems(composedSchema);
   541→    return array;
   542→  }
   543→
   544→  private void applySchemaRestrictions(Schema<?> base) {
   545→    if (base.getType().equals("array")) {
   546→      if (base instanceof ArraySchema arraySchema) {
   547→        for (RestrictionInfo restriction : this.restrictions) {
   548→          restriction.applyToArraySchema(arraySchema);
   549→        }
   550→      }
   551→    } else {
   552→      // NEW: Pattern matching for non-array restrictions
   553→      for (RestrictionInfo restriction : this.restrictions) {
   554→        isRequired |= restriction.impliesRequired();
   555→        switch (restriction) {
   556→          case DataHasValue data -> base.setDefault(data.expression().getFiller().getLiteral());
   557→          case DataOneOf _dataOneOf -> {
   558→            if (CollectionUtils.isNotEmpty(this.valuesFromDataRestrictions_ranges)) {
   559→              if (base instanceof StringSchema stringSchema) {
   560→                this.valuesFromDataRestrictions_ranges.stream().sorted()
   561→                    .forEach(stringSchema::addEnumItemObject);
   562→              }
   563→            }
   564→          }
   565→          default -> {
   566→          }
   567→        }
   568→      }
   569→    }
   570→  }
   571→}
