```

**Updated visitor methods to store typed restrictions:**

```java

@Override
public void visit(OWLObjectSomeValuesFrom ce) {
  for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
    property_name = cleanName(sfp.getShortForm(property.getIRI()));
    if (!propertiesFromObjectRestrictions.contains(property)) {
      propertiesFromObjectRestrictions.add(property);
    }
    // NEW: Store typed restriction
    restrictions.computeIfAbsent(property_name, k -> new ArrayList<>())
        .add(new RestrictionInfo.SomeValuesFrom(ce));
  }
  // ... rest of method
}

@Override
public void visit(OWLObjectMinCardinality ce) {
  setPropertiesWithCardinality(ce);
}

private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
  for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
    property_name = cleanName(sfp.getShortForm(property.getIRI()));
    if (!propertiesFromObjectRestrictions.contains(property)) {
      propertiesFromObjectRestrictions.add(property);
    }
    // NEW: Store typed restriction using factory method
    final String propName = property_name;
    RestrictionInfo.from(ce).ifPresent(info ->
        restrictions.computeIfAbsent(propName, k -> new ArrayList<>()).add(info));
    // ... range handling
  }
}
```

