   232→      case DataMinCardinality r -> schema.setMinItems(r.expression().getCardinality());
   233→      case DataMaxCardinality r -> schema.setMaxItems(r.expression().getCardinality());
   234→      case DataExactCardinality r -> {
   235→        schema.setMinItems(r.expression().getCardinality());
   236→        schema.setMaxItems(r.expression().getCardinality());
